+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {
+  level: number,
+  text: string,
+};
+
+const tocStartRegex = /<!--[ \	]*toc[ \	]*-->/gi;
+const tocEndRegex = /<!--[ \	]*\\/[ \	]*toc[ \	]*-->/gi;
+const atxHeadingRegex = /^(?: {0,3})(#{1,6})[ \	]+(.+?)[ \	]*$/;
+const explicitIdRegex = /[ \	]*\\{#([^\\s}]+)\\}[ \	]*$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const startMatch = tocStartRegex.exec(text);
+    if (!startMatch) {
+      return text;
+    }
+
+    tocEndRegex.lastIndex = startMatch.index + startMatch[0].length;
+    const endMatch = tocEndRegex.exec(text);
+    const tocEnd = endMatch?.index ?? startMatch.index + startMatch[0].length;
+    const headings = this.getHeadings(text, startMatch.index + startMatch[0].length, tocEnd, options);
+    const toc = this.buildToc(headings, options);
+    const before = text.slice(0, startMatch.index);
+    const after = endMatch ? text.slice(endMatch.index + endMatch[0].length) : text.slice(tocEnd);
+    const title = options.title.trim();
+    const body = [
+      '<!-- toc -->',
+      '',
+      ...(title ? [title, ''] : []),
+      ...toc,
+      '',
+      '<!-- /toc -->',
+      '',
+    ].join('\
');
+
+    return before + body + this.withSingleBlankLinePrefix(after);
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [];
+  }
+
+  private withSingleBlankLinePrefix(text: string): string {
+    return text.replace(/^\\r?\
(?:[ \	]*\\r?\
)*/, '');
+  }
+
+  private getHeadings(text: string, tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const lines = text.split(/\\r?\
/);
+    let offset = 0;
+    let fence: string | null = null;
+    let mathBlock = false;
+    let yaml = lines[0]?.trim() === '---';
+
+    for (const line of lines) {
+      const lineEnd = offset + line.length;
+      const trimmed = line.trim();
+      const inToc = offset >= tocStart && lineEnd <= tocEnd;
+
+      if (yaml) {
+        if (offset !== 0 && (trimmed === '---' || trimmed === '...')) {
+          yaml = false;
+        }
+      } else if (fence) {
+        if (new RegExp(`^ {0,3}${fence}[ \\\	]*$`).test(line)) {
+          fence = null;
+        }
+      } else if (/^ {0,3}(`{3,}|~{3,})/.test(line)) {
+        fence = RegExp.$1[0].repeat(RegExp.$1.length);
+      } else if (mathBlock) {
+        if (/^\\$\\$[ \	]*$/.test(trimmed)) {
+          mathBlock = false;
+        }
+      } else if (/^\\$\\$/.test(trimmed)) {
+        const closingDelimiter = trimmed.match(/\\$\\$/g)?.length ?? 0;
+        if (closingDelimiter < 2 || trimmed === '$$') {
+          mathBlock = true;
+        }
+      } else if (!inToc) {
+        const match = line.match(atxHeadingRegex);
+        if (match) {
+          const level = match[1].length;
+          const headingText = this.removeTrailingHeadingMarkers(match[2]);
+          if (level >= options.minLevel && level <= options.maxLevel && !this.isExcluded(headingText, options.excludeHeadings)) {
+            headings.push({level, text: headingText});
+          }
+        }
+      }
+
+      offset = lineEnd + 1;
+    }
+
+    return headings;
+  }
+
+  private buildToc(headings: Heading[], options: AutoTocOptions): string[] {
+    const anchors = new Map<string, number>();
+    return headings.map((heading, index) => {
+      const explicitId = options.useExplicitIds ? heading.text.match(explicitIdRegex)?.[1] : undefined;
+      const labelText = explicitId ? heading.text.replace(explicitIdRegex, '').trimEnd() : heading.text;
+      const label = options.stripFormattingInToc ? this.stripFormatting(labelText) : this.resolveLinksAndImages(labelText);
+      const anchorBase = explicitId ?? this.toAnchor(labelText);
+      const seen = anchors.get(anchorBase) ?? 0;
+      anchors.set(anchorBase, seen + 1);
+      const anchor = seen === 0 ? anchorBase : `${anchorBase}-${seen}`;
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+      const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      return `${indent}${marker} [${label}](#${anchor})`;
+    });
+  }
+
+  private toAnchor(text: string): string {
+    return this.stripFormatting(text)
+        .toLowerCase()
+        .replace(/\\s+/g, '-')
+        .replace(/[^a-z0-9\\-_]/g, '')
+        .replace(/-+/g, '-')
+        .replace(/^-+|-+$/g, '');
+  }
+
+  private stripFormatting(text: string): string {
+    return this.resolveLinksAndImages(this.removeTrailingHeadingMarkers(text))
+        .replace(/[`*_~]/g, '')
+        .replace(/<[^>]*>/g, '')
+        .trim();
+  }
+
+  private resolveLinksAndImages(text: string): string {
+    return text
+        .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+        .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+        .replace(/\\[\\[([^\\]|]+)(?:\\|[^\\]]+)?\\]\\]/g, '$1')
+        .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1')
+        .trim();
+  }
+
+  private removeTrailingHeadingMarkers(text: string): string {
+    return text.replace(/[ \	]+#+[ \	]*$/, '').trim();
+  }
+
+  private isExcluded(heading: string, exclusions: string[]): boolean {
+    const comparableHeading = this.resolveLinksAndImages(heading).toLowerCase();
+    return exclusions.some((exclusion) => {
+      const value = exclusion.trim();
+      if (value.startsWith('/') && value.endsWith('/') && value.length > 2) {
+        try {
+          return new RegExp(value.slice(1, -1), 'i').test(comparableHeading);
+        } catch (_) {
+          return comparableHeading === value.toLowerCase();
+        }
+      }
+      return comparableHeading === value.toLowerCase();
+    });
+  }
